local qc = require(script.Parent.Component)
local rt = qc:extend("PureComponent")
rt.extend = qc.extend
function rt:shouldUpdate(qA, ex)
	if ex ~= self.state then
		return true
	end
	if qA == self.props then
		return false
	end
	for ej, d3 in pairs(qA) do
		if self.props[ej] ~= d3 then
			return true
		end
	end
	for ej, d3 in pairs(self.props) do
		if qA[ej] ~= d3 then
			return true
		end
	end
	return false
end
return rt
